class Solution {
    public int[] validSequence(String word1, String word2) {
        int n = word1.length(), m = word2.length();
        int[] res = new int[m];
        int j = 0, k = 0;
        while (j < n && k < m) {
            if (word1.charAt(j) == word2.charAt(k)) {
                res[k] = j;
                k++;
            }
            j++;
        }
        if (k != m) return new int[0];
        for (int i = 0; i < m; i++) {
            if (i > 0 && res[i] - res[i - 1] > 1) return new int[0];
        }
        return res;
    }
}
